<template><div class="panel"><div class="section-head"><div><h2>模型配置</h2><p>维护供应商下的模型标识和能力等级。</p></div><el-button v-if="auth.hasPermission('model:model:create')" type="primary" @click="open()">新增模型</el-button></div><el-table :data="rows"><el-table-column prop="code" label="编码"/><el-table-column prop="name" label="名称"/><el-table-column label="供应商"><template #default="s">{{providerName(s.row.providerId)}}</template></el-table-column><el-table-column prop="modelName" label="模型标识"/><el-table-column prop="modelType" label="类型"/><el-table-column prop="capabilityLevel" label="能力"/><el-table-column label="操作"><template #default="s"><el-button link type="success" @click="test(s.row)">测试</el-button><el-button link type="primary" @click="open(s.row)">编辑</el-button><el-button link type="danger" @click="remove(s.row)">删除</el-button></template></el-table-column></el-table><el-dialog v-model="visible" :title="form.id?'编辑模型':'新增模型'"><el-form label-width="100px"><el-form-item label="编码"><el-input v-model="form.code"/></el-form-item><el-form-item label="名称"><el-input v-model="form.name"/></el-form-item><el-form-item label="供应商"><el-select v-model="form.providerId"><el-option v-for="item in providers" :key="item.id" :label="item.name" :value="item.id"/></el-select></el-form-item><el-form-item label="模型标识"><el-input v-model="form.modelName"/></el-form-item><el-form-item label="模型类型"><el-select v-model="form.modelType"><el-option label="文本" value="TEXT"/><el-option label="视觉" value="VISION"/></el-select></el-form-item><el-form-item label="能力等级"><el-select v-model="form.capabilityLevel"><el-option label="低" value="LOW"/><el-option label="中" value="MIDDLE"/><el-option label="高" value="HIGH"/></el-select></el-form-item><el-form-item label="启用"><el-switch v-model="form.enabled"/></el-form-item></el-form><template #footer><el-button @click="visible=false">取消</el-button><el-button type="primary" @click="save">保存</el-button></template></el-dialog></div></template>
<script setup>import{onMounted,reactive,ref}from'vue';import{ElMessage,ElMessageBox}from'element-plus';import http from'../api/http';import{useAuthStore}from'../stores/auth';const auth=useAuthStore(),rows=ref([]),providers=ref([]),visible=ref(false),form=reactive({id:null,code:'',name:'',providerId:null,modelName:'',modelType:'TEXT',capabilityLevel:'MIDDLE',enabled:true});async function load(){[rows.value,providers.value]=await Promise.all([http.get('/models').then(r=>r.data),http.get('/models/providers').then(r=>r.data)])}/** 打开模型窗口。 */function open(row){Object.assign(form,row?{...row}:{id:null,code:'',name:'',providerId:null,modelName:'',modelType:'TEXT',capabilityLevel:'MIDDLE',enabled:true});visible.value=true}/** 保存模型。 */async function save(){form.id?await http.put(`/models/${form.id}`,form):await http.post('/models',form);visible.value=false;await load();ElMessage.success('保存成功')}/** 测试模型连接。 */async function test(row){const result=(await http.post(`/models/${row.id}/test`)).data;ElMessage.success(`连接成功，耗时 ${result.durationMs}ms`)}/** 删除模型。 */async function remove(row){await ElMessageBox.confirm(`确认删除模型「${row.name}」？`);await http.delete(`/models/${row.id}`);await load()}function providerName(id){return providers.value.find(item=>item.id===id)?.name||id}onMounted(load)</script>
<!-- 模型管理页面：维护模型元数据并提供连通性测试。 -->
